PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS Collection (id TEXT PRIMARY KEY NOT NULL, slug TEXT NOT NULL UNIQUE, name TEXT NOT NULL, description TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS Product (id TEXT PRIMARY KEY NOT NULL, slug TEXT NOT NULL UNIQUE, name TEXT NOT NULL, description TEXT NOT NULL, priceVnd INTEGER NOT NULL, published BOOLEAN NOT NULL DEFAULT false, collectionId TEXT, createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updatedAt DATETIME NOT NULL, FOREIGN KEY (collectionId) REFERENCES Collection(id));
CREATE TABLE IF NOT EXISTS ProductImage (id TEXT PRIMARY KEY NOT NULL, productId TEXT NOT NULL, src TEXT NOT NULL, alt TEXT NOT NULL, position INTEGER NOT NULL DEFAULT 0, FOREIGN KEY (productId) REFERENCES Product(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS ProductVariant (id TEXT PRIMARY KEY NOT NULL, productId TEXT NOT NULL, size TEXT NOT NULL, sku TEXT NOT NULL UNIQUE, stock INTEGER NOT NULL, createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (productId) REFERENCES Product(id) ON DELETE CASCADE);
CREATE UNIQUE INDEX IF NOT EXISTS ProductVariant_productId_size_key ON ProductVariant(productId, size);
CREATE TABLE IF NOT EXISTS CampaignMedia (id TEXT PRIMARY KEY NOT NULL, title TEXT NOT NULL, kind TEXT NOT NULL, src TEXT NOT NULL, alt TEXT NOT NULL, hero BOOLEAN NOT NULL DEFAULT false, position INTEGER NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS "Order" (id TEXT PRIMARY KEY NOT NULL, orderNumber TEXT NOT NULL UNIQUE, email TEXT NOT NULL, customerName TEXT NOT NULL, phone TEXT NOT NULL, country TEXT NOT NULL, addressLine1 TEXT NOT NULL, addressLine2 TEXT, city TEXT NOT NULL, province TEXT, postalCode TEXT, subtotalVnd INTEGER NOT NULL, shippingVnd INTEGER NOT NULL, totalVnd INTEGER NOT NULL, status TEXT NOT NULL DEFAULT 'PENDING_PAYMENT', createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updatedAt DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS OrderItem (id TEXT PRIMARY KEY NOT NULL, orderId TEXT NOT NULL, productId TEXT NOT NULL, variantId TEXT NOT NULL, productName TEXT NOT NULL, size TEXT NOT NULL, unitPriceVnd INTEGER NOT NULL, quantity INTEGER NOT NULL, FOREIGN KEY (orderId) REFERENCES "Order"(id) ON DELETE CASCADE, FOREIGN KEY (productId) REFERENCES Product(id));
CREATE TABLE IF NOT EXISTS Payment (id TEXT PRIMARY KEY NOT NULL, orderId TEXT NOT NULL, provider TEXT NOT NULL, providerRef TEXT UNIQUE, checkoutUrl TEXT, status TEXT NOT NULL DEFAULT 'CREATED', amountVnd INTEGER NOT NULL, rawPayload TEXT, createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updatedAt DATETIME NOT NULL, FOREIGN KEY (orderId) REFERENCES "Order"(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS AdminUser (id TEXT PRIMARY KEY NOT NULL, email TEXT NOT NULL UNIQUE, passwordHash TEXT NOT NULL, role TEXT NOT NULL DEFAULT 'ADMIN', createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
